import React from 'react';
import api from '../api/axiosSetup';

const TaskItem = ({ task, refreshTasks }) => {

  const handleDelete = async () => {
    try {
      await api.delete(`/tasks/${task.id}`);
      refreshTasks();
    } catch (err) {
      alert('Failed to delete task.');
    }
  };

  const handleToggle = async () => {
    try {
      await api.put(`/tasks/${task.id}`, { 
        status: task.status === 'COMPLETED' ? 'PENDING' : 'COMPLETED' 
      });
      refreshTasks();
    } catch (err) {
      alert('Failed to update task status.');
    }
  };

  return (
    <div style={{ 
      border: '1px solid #d1d5db', 
      padding: '15px', 
      borderRadius: '6px',
      background: task.status === 'COMPLETED' ? '#f3f4f6' : 'white',
      opacity: task.status === 'COMPLETED' ? 0.7 : 1
    }}>
      <h3 style={{ margin: '0 0 10px 0', textDecoration: task.status === 'COMPLETED' ? 'line-through' : 'none' }}>
        {task.title}
      </h3>
      <p style={{ margin: '0 0 15px 0', color: '#4b5563' }}>{task.description}</p>

      <div style={{ display: 'flex', gap: '10px' }}>
        <button 
          onClick={handleToggle}
          style={{ padding: '6px 12px', background: '#10b981', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          {task.status === 'COMPLETED' ? 'Mark Pending' : 'Mark Completed'}
        </button>
        <button 
          onClick={handleDelete} 
          style={{ padding: '6px 12px', background: '#ef4444', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          Delete
        </button>
      </div>
    </div>
  );
};

export default TaskItem;

